import{_ as s,o as n,c as e,ag as o}from"./chunks/framework.DXGyWiRo.js";const y=JSON.parse('{"title":"MariaDB Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guides/mariadb.md","filePath":"guides/mariadb.md"}'),t={name:"guides/mariadb.md"};function l(p,a,i,r,c,d){return n(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="mariadb-guide" tabindex="-1">MariaDB Guide <a class="header-anchor" href="#mariadb-guide" aria-label="Permalink to &quot;MariaDB Guide&quot;">​</a></h1><p><code>MariaDBClient</code> is the direct MariaDB client for LinkedQL. It gives you full SQL access and transactions over a native MariaDB connection, with planned realtime capabilities built on MariaDB&#39;s binlog.</p><p>Use <code>MariaDBClient</code> when your application talks directly to MariaDB.</p><blockquote><p><code>MariaDBClient</code> uses the native <code>mariadb</code> connector under the hood and accepts all the existing constructor options.</p></blockquote><hr><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> MariaDBClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/mariadb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> MariaDBClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 3306</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">root</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mydb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 1 AS \`result\`</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ result: 1 }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="connection-mode" tabindex="-1">Connection Mode <a class="header-anchor" href="#connection-mode" aria-label="Permalink to &quot;Connection Mode&quot;">​</a></h2><p><code>MariaDBClient</code> always runs on a pool-backed connection model.</p><p>That means the MariaDB guide differs slightly from PostgreSQL and MySQL: there is no <code>poolMode</code> switch here because pooling is the default operating model of the client.</p><p>In every other way, however, <code>MariaDBClient</code> follows the same common contract as the other clients. For example, calling <code>db.connect()</code> returns a checked-out client for use.</p><hr><h2 id="realtime-setup" tabindex="-1">Realtime Setup <a class="header-anchor" href="#realtime-setup" aria-label="Permalink to &quot;Realtime Setup&quot;">​</a></h2><p>As in the MySQL setup, LinkedQL is designed to integrate with MariaDB&#39;s binary log (binlog) for realtime capabilities.</p><p>To make this possible, binary logging must be enabled on the MariaDB server.</p><p>At minimum, set in your database config file:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>log_bin = ON</span></span></code></pre></div><p>For correct change capture, row-based logging is recommended:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>binlog_format = ROW</span></span></code></pre></div><p>Refer to the official MariaDB documentation for enabling and configuring binary logging.</p><p>Once binary logging is available, LinkedQL can build on top of it for realtime features.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Realtime capabilities, specifically live queries and commit stream subscriptions, are not yet available on MariaDB. Support for these features is planned and will build on the binlog-based foundation.</p></div><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">how this fits into larger app architectures</td><td style="text-align:left;"><a href="/guides/integration-patterns">Integration Patterns</a></td></tr><tr><td style="text-align:left;">the common API contract</td><td style="text-align:left;"><a href="/api">API</a></td></tr></tbody></table>`,26)])])}const F=s(t,[["render",l]]);export{y as __pageData,F as default};
